import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';

const Payment = () => {
  const [bookingData, setBookingData] = useState(null);
  const [paymentMethod, setPaymentMethod] = useState('card');
  const [formData, setFormData] = useState({
    cardNumber: '',
    cardName: '',
    expiryDate: '',
    cvv: '',
    upiId: '',
    bankName: '',
    accountNumber: '',
    ifscCode: ''
  });
  const [processing, setProcessing] = useState(false);
  const [errors, setErrors] = useState({});
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    const storedBooking = localStorage.getItem('bookingData');
    if (storedBooking) {
      setBookingData(JSON.parse(storedBooking));
    } else if (location.state?.bookingData) {
      setBookingData(location.state.bookingData);
    } else {
      navigate('/seats');
    }
  }, [navigate, location.state]);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const validateForm = () => {
    const newErrors = {};

    if (paymentMethod === 'card') {
      if (!formData.cardNumber) newErrors.cardNumber = 'Card number is required';
      else if (!/^\d{16}$/.test(formData.cardNumber.replace(/\s/g, ''))) 
        newErrors.cardNumber = 'Invalid card number';

      if (!formData.cardName) newErrors.cardName = 'Cardholder name is required';

      if (!formData.expiryDate) newErrors.expiryDate = 'Expiry date is required';
      else if (!/^(0[1-9]|1[0-2])\/\d{2}$/.test(formData.expiryDate))
        newErrors.expiryDate = 'Invalid expiry date (MM/YY)';

      if (!formData.cvv) newErrors.cvv = 'CVV is required';
      else if (!/^\d{3,4}$/.test(formData.cvv))
        newErrors.cvv = 'Invalid CVV';
    }

    if (paymentMethod === 'upi') {
      if (!formData.upiId) newErrors.upiId = 'UPI ID is required';
      else if (!/^[a-zA-Z0-9._-]+@[a-zA-Z0-9.-]+$/.test(formData.upiId))
        newErrors.upiId = 'Invalid UPI ID';
    }

    if (paymentMethod === 'netbanking') {
      if (!formData.bankName) newErrors.bankName = 'Bank name is required';
      if (!formData.accountNumber) newErrors.accountNumber = 'Account number is required';
      if (!formData.ifscCode) newErrors.ifscCode = 'IFSC code is required';
      else if (!/^[A-Z]{4}0[A-Z0-9]{6}$/.test(formData.ifscCode))
        newErrors.ifscCode = 'Invalid IFSC code';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handlePayment = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;

    setProcessing(true);

    // Simulate payment processing
    setTimeout(() => {
      setProcessing(false);

      // Store payment confirmation
      const paymentData = {
        ...bookingData,
        paymentMethod,
        paymentId: 'PAY' + Date.now(),
        paymentStatus: 'Success',
        paymentTime: new Date().toISOString()
      };

      localStorage.setItem('bookingData', JSON.stringify(paymentData));
      navigate('/confirmation');
    }, 3000);
  };

  const formatCardNumber = (value) => {
    const v = value.replace(/\s+/g, '').replace(/[^0-9]/gi, '');
    const matches = v.match(/\d{4,16}/g);
    const match = matches && matches[0] || '';
    const parts = [];
    for (let i = 0, len = match.length; i < len; i += 4) {
      parts.push(match.substring(i, i + 4));
    }
    if (parts.length) {
      return parts.join(' ');
    } else {
      return v;
    }
  };

  const getCardType = (number) => {
    const n = number.replace(/\s/g, '');
    if (/^4/.test(n)) return 'visa';
    if (/^5[1-5]/.test(n)) return 'mastercard';
    if (/^3[47]/.test(n)) return 'amex';
    return '';
  };

  if (!bookingData) {
    return <div>Loading payment information...</div>;
  }

  return (
    <div className="container">
      <div className="card" style={{ maxWidth: '600px', margin: '50px auto' }}>
        <h2>Payment</h2>

        <div style={{ background: '#f8f9fa', padding: '15px', borderRadius: '5px', marginBottom: '20px' }}>
          <h4>Booking Summary</h4>
          <p><strong>Bus:</strong> {bookingData.bus.busName}</p>
          <p><strong>Route:</strong> {bookingData.bus.departure} - {bookingData.bus.arrival}</p>
          <p><strong>Seats:</strong> {bookingData.seats.map(s => s.number).join(', ')}</p>
          <p><strong>Amount:</strong> <span style={{ fontSize: '18px', color: '#007bff', fontWeight: 'bold' }}>
            ₹{bookingData.totalPrice}
          </span></p>
        </div>

        <form onSubmit={handlePayment}>
          <div className="form-group">
            <label>Select Payment Method</label>
            <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
              <button
                type="button"
                className={paymentMethod === 'card' ? 'btn' : 'btn btn-secondary'}
                onClick={() => setPaymentMethod('card')}
                style={{ flex: 1 }}
              >
                💳 Card
              </button>
              <button
                type="button"
                className={paymentMethod === 'upi' ? 'btn' : 'btn btn-secondary'}
                onClick={() => setPaymentMethod('upi')}
                style={{ flex: 1 }}
              >
                📱 UPI
              </button>
              <button
                type="button"
                className={paymentMethod === 'netbanking' ? 'btn' : 'btn btn-secondary'}
                onClick={() => setPaymentMethod('netbanking')}
                style={{ flex: 1 }}
              >
                🏦 Net Banking
              </button>
            </div>
          </div>

          {paymentMethod === 'card' && (
            <div>
              <h4>Card Details</h4>

              <div className="form-group">
                <label>Card Number *</label>
                <input
                  type="text"
                  name="cardNumber"
                  value={formData.cardNumber}
                  onChange={(e) => {
                    const formatted = formatCardNumber(e.target.value);
                    setFormData({...formData, cardNumber: formatted});
                  }}
                  placeholder="1234 5678 9012 3456"
                  maxLength="19"
                />
                {errors.cardNumber && <div style={{ color: 'red', fontSize: '12px' }}>{errors.cardNumber}</div>}
                {getCardType(formData.cardNumber) && (
                  <div style={{ fontSize: '12px', color: '#666', marginTop: '5px' }}>
                    Card type: {getCardType(formData.cardNumber).toUpperCase()}
                  </div>
                )}
              </div>

              <div className="form-group">
                <label>Cardholder Name *</label>
                <input
                  type="text"
                  name="cardName"
                  value={formData.cardName}
                  onChange={handleChange}
                  placeholder="John Doe"
                />
                {errors.cardName && <div style={{ color: 'red', fontSize: '12px' }}>{errors.cardName}</div>}
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
                <div className="form-group">
                  <label>Expiry Date *</label>
                  <input
                    type="text"
                    name="expiryDate"
                    value={formData.expiryDate}
                    onChange={(e) => {
                      let value = e.target.value.replace(/\D/g, '');
                      if (value.length >= 2) {
                        value = value.slice(0, 2) + '/' + value.slice(2, 4);
                      }
                      setFormData({...formData, expiryDate: value});
                    }}
                    placeholder="MM/YY"
                    maxLength="5"
                  />
                  {errors.expiryDate && <div style={{ color: 'red', fontSize: '12px' }}>{errors.expiryDate}</div>}
                </div>

                <div className="form-group">
                  <label>CVV *</label>
                  <input
                    type="text"
                    name="cvv"
                    value={formData.cvv}
                    onChange={(e) => {
                      const value = e.target.value.replace(/\D/g, '').slice(0, 4);
                      setFormData({...formData, cvv: value});
                    }}
                    placeholder="123"
                    maxLength="4"
                  />
                  {errors.cvv && <div style={{ color: 'red', fontSize: '12px' }}>{errors.cvv}</div>}
                </div>
              </div>
            </div>
          )}

          {paymentMethod === 'upi' && (
            <div>
              <h4>UPI Details</h4>

              <div className="form-group">
                <label>UPI ID *</label>
                <input
                  type="text"
                  name="upiId"
                  value={formData.upiId}
                  onChange={handleChange}
                  placeholder="yourname@upi"
                />
                {errors.upiId && <div style={{ color: 'red', fontSize: '12px' }}>{errors.upiId}</div>}
              </div>

              <div style={{ 
                background: '#e3f2fd', 
                padding: '15px', 
                borderRadius: '5px', 
                marginBottom: '20px',
                textAlign: 'center'
              }}>
                <p style={{ margin: '0', color: '#1976d2' }}>
                  📱 You will receive a payment request on your UPI app
                </p>
              </div>
            </div>
          )}

          {paymentMethod === 'netbanking' && (
            <div>
              <h4>Net Banking Details</h4>

              <div className="form-group">
                <label>Select Bank *</label>
                <select
                  name="bankName"
                  value={formData.bankName}
                  onChange={handleChange}
                >
                  <option value="">Select your bank</option>
                  <option value="SBI">State Bank of India</option>
                  <option value="HDFC">HDFC Bank</option>
                  <option value="ICICI">ICICI Bank</option>
                  <option value="PNB">Punjab National Bank</option>
                  <option value="AXIS">Axis Bank</option>
                  <option value="KOTAK">Kotak Mahindra Bank</option>
                </select>
                {errors.bankName && <div style={{ color: 'red', fontSize: '12px' }}>{errors.bankName}</div>}
              </div>

              <div className="form-group">
                <label>Account Number *</label>
                <input
                  type="text"
                  name="accountNumber"
                  value={formData.accountNumber}
                  onChange={handleChange}
                  placeholder="Your bank account number"
                />
                {errors.accountNumber && <div style={{ color: 'red', fontSize: '12px' }}>{errors.accountNumber}</div>}
              </div>

              <div className="form-group">
                <label>IFSC Code *</label>
                <input
                  type="text"
                  name="ifscCode"
                  value={formData.ifscCode}
                  onChange={(e) => {
                    const value = e.target.value.toUpperCase();
                    setFormData({...formData, ifscCode: value});
                  }}
                  placeholder="SBIN0000000"
                />
                {errors.ifscCode && <div style={{ color: 'red', fontSize: '12px' }}>{errors.ifscCode}</div>}
              </div>
            </div>
          )}

          <div style={{ 
            background: '#fff3cd', 
            border: '1px solid #ffeaa7', 
            padding: '15px', 
            borderRadius: '5px',
            marginBottom: '20px'
          }}>
            <h4 style={{ color: '#856404', marginBottom: '10px' }}>Security Notice</h4>
            <ul style={{ margin: '0', paddingLeft: '20px', color: '#856404', fontSize: '14px' }}>
              <li>Your payment information is encrypted and secure</li>
              <li>We do not store your card details on our servers</li>
              <li>This transaction is protected by industry-standard security</li>
            </ul>
          </div>

          <div style={{ display: 'flex', gap: '10px' }}>
            <button 
              type="button" 
              className="btn btn-secondary" 
              onClick={() => navigate('/seats')}
              style={{ flex: 1 }}
            >
              Back
            </button>
            <button 
              type="submit" 
              className="btn" 
              disabled={processing}
              style={{ flex: 2 }}
            >
              {processing ? 'Processing...' : `Pay ₹${bookingData.totalPrice}`}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Payment;
